export class RetryPolicy {
  execute<T>(fn: () => T, retries: number): T {
    let attempts = 0;
    while (true) {
      try {
        return fn();
      } catch (err) {
        attempts++;
        if (attempts > retries) {
          throw err;
        }
      }
    }
  }
}

